import{_ as e,o as s,c as i,a2 as n}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Imágenes y recursos visuales","description":"","frontmatter":{},"headers":[],"relativePath":"recursos/imagenes/01-introduccion.md","filePath":"recursos/imagenes/01-introduccion.md","lastUpdated":1782521464000}'),r={name:"recursos/imagenes/01-introduccion.md"};function l(o,a,t,c,d,p){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="imagenes-y-recursos-visuales" tabindex="-1">Imágenes y recursos visuales <a class="header-anchor" href="#imagenes-y-recursos-visuales" aria-label="Permalink to &quot;Imágenes y recursos visuales&quot;">​</a></h1><p>Esta carpeta centraliza imágenes, diagramas, capturas y recursos visuales que pueden acompañar los manuales técnicos del repositorio o una futura web de documentación.</p><h2 id="objetivo" tabindex="-1">Objetivo <a class="header-anchor" href="#objetivo" aria-label="Permalink to &quot;Objetivo&quot;">​</a></h2><p>Los recursos visuales deben ayudar a entender conceptos técnicos, no decorar sin aportar información. Un buen diagrama puede explicar arquitectura, flujos de datos, relaciones entre componentes o pasos de un proceso mejor que varios párrafos.</p><h2 id="tipos-de-imagenes-recomendadas" tabindex="-1">Tipos de imágenes recomendadas <a class="header-anchor" href="#tipos-de-imagenes-recomendadas" aria-label="Permalink to &quot;Tipos de imágenes recomendadas&quot;">​</a></h2><h3 id="diagramas-de-arquitectura" tabindex="-1">Diagramas de arquitectura <a class="header-anchor" href="#diagramas-de-arquitectura" aria-label="Permalink to &quot;Diagramas de arquitectura&quot;">​</a></h3><p>Útiles para explicar cómo se conectan frontend, backend, bases de datos, servicios externos y despliegues.</p><p>Ejemplos:</p><ul><li>Arquitectura full stack.</li><li>Flujo de autenticación.</li><li>Comunicación frontend-backend.</li><li>Arquitectura de pipelines de datos.</li></ul><h3 id="diagramas-de-flujo" tabindex="-1">Diagramas de flujo <a class="header-anchor" href="#diagramas-de-flujo" aria-label="Permalink to &quot;Diagramas de flujo&quot;">​</a></h3><p>Sirven para representar procesos paso a paso.</p><p>Ejemplos:</p><ul><li>Pipeline de ingesta.</li><li>Flujo de login.</li><li>Proceso de despliegue.</li><li>Ciclo de vida de una petición HTTP.</li></ul><h3 id="capturas-de-pantalla" tabindex="-1">Capturas de pantalla <a class="header-anchor" href="#capturas-de-pantalla" aria-label="Permalink to &quot;Capturas de pantalla&quot;">​</a></h3><p>Útiles cuando el manual depende de una herramienta visual.</p><p>Ejemplos:</p><ul><li>Interfaz de Apache NiFi.</li><li>Panel de Snowflake.</li><li>Consola de Databricks.</li><li>Resultado de una aplicación frontend.</li></ul><h3 id="esquemas-conceptuales" tabindex="-1">Esquemas conceptuales <a class="header-anchor" href="#esquemas-conceptuales" aria-label="Permalink to &quot;Esquemas conceptuales&quot;">​</a></h3><p>Ayudan a resumir ideas complejas.</p><p>Ejemplos:</p><ul><li>RDD, DataFrame y Dataset en Spark.</li><li>Roles, warehouses y schemas en Snowflake.</li><li>Componentes, servicios y módulos en Angular.</li><li>Props, state y hooks en React.</li></ul><h2 id="estructura-recomendada" tabindex="-1">Estructura recomendada <a class="header-anchor" href="#estructura-recomendada" aria-label="Permalink to &quot;Estructura recomendada&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imagenes/</span></span>
<span class="line"><span>├── arquitectura/</span></span>
<span class="line"><span>├── data-engineering/</span></span>
<span class="line"><span>├── frontend/</span></span>
<span class="line"><span>├── bases-de-datos/</span></span>
<span class="line"><span>├── herramientas/</span></span>
<span class="line"><span>└── capturas/</span></span></code></pre></div><p>Puedes crear subcarpetas cuando haya suficientes recursos para justificarlo. Evita crear carpetas vacías sin propósito.</p><h2 id="convenciones-de-nombres" tabindex="-1">Convenciones de nombres <a class="header-anchor" href="#convenciones-de-nombres" aria-label="Permalink to &quot;Convenciones de nombres&quot;">​</a></h2><p>Usa nombres descriptivos, en minúsculas y con guiones medios.</p><p>Buenos ejemplos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>arquitectura-full-stack-api-db.png</span></span>
<span class="line"><span>pipeline-nifi-spark-snowflake.png</span></span>
<span class="line"><span>react-flujo-estado-componentes.png</span></span>
<span class="line"><span>spark-driver-executors.png</span></span>
<span class="line"><span>docker-compose-servicios.png</span></span></code></pre></div><p>Evita nombres ambiguos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imagen1.png</span></span>
<span class="line"><span>captura-final.png</span></span>
<span class="line"><span>nuevo-diagrama.png</span></span>
<span class="line"><span>foto.png</span></span></code></pre></div><h2 id="formatos-recomendados" tabindex="-1">Formatos recomendados <a class="header-anchor" href="#formatos-recomendados" aria-label="Permalink to &quot;Formatos recomendados&quot;">​</a></h2><ul><li><strong>SVG:</strong> diagramas simples, iconografía y esquemas escalables.</li><li><strong>PNG:</strong> capturas de pantalla o imágenes con detalle.</li><li><strong>JPG/JPEG:</strong> fotografías o imágenes pesadas sin transparencia.</li><li><strong>WebP:</strong> imágenes optimizadas para web.</li></ul><p>Para una web de documentación, prioriza SVG o WebP cuando sea posible.</p><h2 id="buenas-practicas" tabindex="-1">Buenas prácticas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas prácticas&quot;">​</a></h2><ul><li>Usa imágenes solo cuando aporten claridad.</li><li>Mantén un estilo visual coherente.</li><li>Optimiza peso antes de publicar.</li><li>Evita capturas con datos sensibles.</li><li>No incluyas tokens, emails privados, claves o rutas internas.</li><li>Añade texto alternativo cuando enlaces imágenes desde un manual.</li><li>Actualiza imágenes si cambia la interfaz o arquitectura documentada.</li></ul><h2 id="como-enlazar-imagenes-desde-un-manual" tabindex="-1">Cómo enlazar imágenes desde un manual <a class="header-anchor" href="#como-enlazar-imagenes-desde-un-manual" aria-label="Permalink to &quot;Cómo enlazar imágenes desde un manual&quot;">​</a></h2><p>Ejemplo desde un documento Markdown:</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">![</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Arquitectura full stack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">../../recursos/imagenes/arquitectura/arquitectura-full-stack-api-db.png</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Si la imagen necesita explicación, añade una breve introducción antes o después.</p><h2 id="checklist-antes-de-anadir-una-imagen" tabindex="-1">Checklist antes de añadir una imagen <a class="header-anchor" href="#checklist-antes-de-anadir-una-imagen" aria-label="Permalink to &quot;Checklist antes de añadir una imagen&quot;">​</a></h2><ul><li>El nombre describe el contenido.</li><li>La imagen no contiene información sensible.</li><li>El peso es razonable.</li><li>El formato es adecuado.</li><li>La ruta relativa funciona.</li><li>El manual explica por qué esa imagen es relevante.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Añadir capturas sin contexto.</li><li>Usar imágenes demasiado pesadas.</li><li>Repetir el mismo diagrama en varias carpetas.</li><li>Guardar recursos con nombres genéricos.</li><li>Publicar capturas con credenciales, rutas privadas o datos personales.</li></ul><h2 id="recursos-relacionados" tabindex="-1">Recursos relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos relacionados&quot;">​</a></h2><ul><li><a href="./../plantillas/README">Plantillas</a></li><li><a href="./../../full-stack/arquitectura/01-introduccion">Arquitectura full stack</a></li><li><a href="./../../data-engineering/pipelines/README">Pipelines de datos</a></li><li><a href="./../../herramientas/docker/01-introduccion">Docker</a></li></ul>`,45)])])}const h=e(r,[["render",l]]);export{m as __pageData,h as default};
